#ifndef fp
typedef float fp;
#endif

#define MAX_LOCAL_SIZE 1024

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    size_t ei = get_global_id(0);

    if ((long)ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    size_t ei = get_global_id(0);

    if ((long)ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int blocks2_work_size)
{
    size_t lid = get_local_id(0);
    size_t lsize = get_local_size(0);
    size_t group = get_group_id(0);
    size_t ei = group * lsize + lid;

    __local fp psum[MAX_LOCAL_SIZE];
    __local fp psum2[MAX_LOCAL_SIZE];

    fp v = (fp)0.0f;
    fp v2 = (fp)0.0f;

    if (lid < MAX_LOCAL_SIZE && (long)ei < d_no) {
        size_t src = ei * (size_t)d_mul;
        v = d_sums[src];
        v2 = d_sums2[src];
    }

    if (lid < MAX_LOCAL_SIZE) {
        psum[lid] = v;
        psum2[lid] = v2;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (size_t stride = lsize >> 1; stride > 0; stride >>= 1) {
        if (lid < stride && lid + stride < MAX_LOCAL_SIZE) {
            psum[lid] += psum[lid + stride];
            psum2[lid] += psum2[lid + stride];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (lid == 0) {
        size_t dst = group * (size_t)d_mul * lsize;
        d_sums[dst] = psum[0];
        d_sums2[dst] = psum2[0];
    }

    (void)d_Ne;
    (void)blocks2_work_size;
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *d_iN,
                          __global int *d_iS,
                          __global int *d_jE,
                          __global int *d_jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    size_t k = get_global_id(0);

    if ((long)k < Ne) {
        int i = (int)(k / (size_t)Nc);
        int j = (int)(k % (size_t)Nc);

        fp Jc = d_I[k];

        fp dN = d_I[(size_t)d_iN[i] * (size_t)Nc + (size_t)j] - Jc;
        fp dS = d_I[(size_t)d_iS[i] * (size_t)Nc + (size_t)j] - Jc;
        fp dW = d_I[(size_t)i * (size_t)Nc + (size_t)d_jW[j]] - Jc;
        fp dE = d_I[(size_t)i * (size_t)Nc + (size_t)d_jE[j]] - Jc;

        d_dN[k] = dN;
        d_dS[k] = dS;
        d_dW[k] = dW;
        d_dE[k] = dE;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = ((fp)0.5f * G2) - ((fp)0.0625f * L * L);
        fp den = (fp)1.0f + ((fp)0.25f * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) {
            c = (fp)0.0f;
        } else if (c > (fp)1.0f) {
            c = (fp)1.0f;
        }

        d_c[k] = c;
    }

    (void)lambda;
    (void)Nr;
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *d_iN,
                           __global int *d_iS,
                           __global int *d_jE,
                           __global int *d_jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    size_t k = get_global_id(0);

    if ((long)k < Ne) {
        int i = (int)(k / (size_t)Nc);
        int j = (int)(k % (size_t)Nc);

        fp cN = d_c[k];
        fp cS = d_c[(size_t)d_iS[i] * (size_t)Nc + (size_t)j];
        fp cW = d_c[k];
        fp cE = d_c[(size_t)i * (size_t)Nc + (size_t)d_jE[j]];

        fp D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];
        d_I[k] = d_I[k] + ((fp)0.25f * lambda * D);
    }

    (void)Nr;
    (void)d_iN;
    (void)d_jW;
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    size_t ei = get_global_id(0);

    if ((long)ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
